public class TemperatureGrid {
    private double[][] grid;
    private int days;
    private int cities;

    public TemperatureGrid(int days, int cities, double[] readings) {
        this.days = days;
        this.cities = cities;
        grid = new double[days][cities];
        for (int r = 0; r < days; r++) {
            for (int c = 0; c < cities; c++) {
                grid[r][c] = readings[r * cities + c];
            }
        }
    }

    public double cityAverage(int cityIndex) {
        double sum = 0.0;
        for (int r = 0; r < days; r++) {
            sum += grid[r][cityIndex];
        }
        return sum / days;
    }
}

