public class GridUtils {
    private static boolean rowsEqual(int[] row1, int[] row2) {
        if (row1.length != row2.length) {
            return false;
        }
        for (int i = 0; i < row1.length; i++) {
            if (row1[i] != row2[i]) {
                return false;
            }
        }
        return true;
    }

    public static int[][] eliminateDuplicateRows(int[][] grid) {
        int uniqueCount = 0;
        for (int i = 0; i < grid.length; i++) {
            boolean isDup = false;
            for (int j = 0; j < i; j++) {
                if (rowsEqual(grid[i], grid[j])) {
                    isDup = true;
                }
            }
            if (!isDup) {
                uniqueCount++;
            }
        }
        int[][] result = new int[uniqueCount][grid[0].length];
        int nextRow = 0;
        for (int i = 0; i < grid.length; i++) {
            boolean isDup = false;
            for (int j = 0; j < i; j++) {
                if (rowsEqual(grid[i], grid[j])) {
                    isDup = true;
                }
            }
            if (!isDup) {
                for (int c = 0; c < grid[i].length; c++) {
                    result[nextRow][c] = grid[i][c];
                }
                nextRow++;
            }
        }
        return result;
    }
}

