public class ScoreMatrix {
    public static int rowSum(int[][] scores, int row) {
        int sum = 0;
        for (int c = 0; c < scores[row].length; c++) {
            sum += scores[row][c];
        }
        return sum;
    }

    public static int[][] keepStrongRows(int[][] scores, int threshold) {
        int count = 0;
        for (int r = 0; r < scores.length; r++) {
            if (rowSum(scores, r) >= threshold) {
                count++;
            }
        }
        int[][] result = new int[count][scores[0].length];
        int idx = 0;
        for (int r = 0; r < scores.length; r++) {
            if (rowSum(scores, r) >= threshold) {
                for (int c = 0; c < scores[r].length; c++) {
                    result[idx][c] = scores[r][c];
                }
                idx++;
            }
        }
        return result;
    }
}

