public class GridUtils {
    public static int[][] filterRows(int[][] grid, int threshold) {
        int count = 0;
        for (int r = 0; r < grid.length; r++) {
            int sum = 0;
            for (int c = 0; c < grid[r].length; c++) {
                sum += grid[r][c];
            }
            if (sum > threshold) {
                count++;
            }
        }

        int[][] result = new int[count][];
        int idx = 0;
        for (int r = 0; r < grid.length; r++) {
            int sum = 0;
            for (int c = 0; c < grid[r].length; c++) {
                sum += grid[r][c];
            }
            if (sum > threshold) {
                int[] copy = new int[grid[r].length];
                for (int c = 0; c < grid[r].length; c++) {
                    copy[c] = grid[r][c];
                }
                result[idx] = copy;
                idx++;
            }
        }
        return result;
    }
}

