public class Warehouse {
    private String[][] inventory;

    public Warehouse(int rows, int cols) {
        inventory = new String[rows][cols];
    }

    public boolean addItem(String item) {
        for (int r = 0; r < inventory.length; r++) {
            for (int c = 0; c < inventory[0].length; c++) {
                if (inventory[r][c] == null) {
                    inventory[r][c] = item;
                    return true;
                }
            }
        }
        return false;
    }

    public String getItem(int r, int c) {
        return inventory[r][c];
    }
}

